// Format a submission payload into a plain-text email body
function formatEmailBody(payload) {
  const lines = [];
  lines.push("New " + (payload.kind || "submission") + " from " + SITE_ID);
  lines.push("Time: " + (payload.timestamp || new Date().toISOString()));
  if (payload.area) lines.push("Practice area: " + payload.area);
  lines.push("");
  const skip = new Set(["kind", "site", "timestamp"]);
  for (const [k, v] of Object.entries(payload)) {
    if (skip.has(k) || v == null || v === "") continue;
    const label = k.replace(/_/g, " ").replace(/\b\w/g, c => c.toUpperCase());
    lines.push(label + ": " + v);
  }
  return lines.join("\n");
}

function formatEmailSubject(payload) {
  const kind = payload.kind === "intake" ? "Intake"
            : payload.kind === "booking" ? "Booking"
            : payload.kind === "chat" ? "Chat message"
            : "Submission";
  const who = payload.client_name || payload.name || "someone";
  const what = payload.area ? " (" + payload.area + ")" : "";
  return "[" + SITE_ID + "] " + kind + what + " — " + who;
}

// Resend API — free 100/day, simplest to set up.
// Requires: wrangler secret put RESEND_API_KEY
async function sendViaResend(env, to, subject, body, replyTo) {
  if (!env || !env.RESEND_API_KEY) return false;
  try {
    const res = await fetch("https://api.resend.com/emails", {
      method: "POST",
      headers: {
        "Authorization": "Bearer " + env.RESEND_API_KEY,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        from: FROM_NAME + " <" + FROM_EMAIL + ">",
        to: [to],
        subject: subject,
        text: body,
        reply_to: replyTo || undefined,
      }),
    });
    return res.ok;
  } catch (e) { return false; }
}

// MailChannels — free, works from Cloudflare Workers if the sending domain has
// SPF/DKIM configured. Best-effort fallback if Resend isn't set up.
async function sendViaMailChannels(to, subject, body, replyTo) {
  try {
    const res = await fetch("https://api.mailchannels.net/tx/v1/send", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        personalizations: [{ to: [{ email: to }] }],
        from: { email: FROM_EMAIL, name: FROM_NAME },
        reply_to: replyTo ? { email: replyTo } : undefined,
        subject: subject,
        content: [{ type: "text/plain", value: body }],
      }),
    });
    return res.ok;
  } catch (e) { return false; }
}

async function sendFallbackEmail(env, payload) {
  if (!FALLBACK_EMAIL) return false;
  const subject = formatEmailSubject(payload);
  const body = formatEmailBody(payload);
  const replyTo = payload.client_email || payload.email || undefined;
  // Try Resend first (most reliable), then MailChannels as last resort
  if (await sendViaResend(env, FALLBACK_EMAIL, subject, body, replyTo)) return true;
  if (await sendViaMailChannels(FALLBACK_EMAIL, subject, body, replyTo)) return true;
  return false;
}

async function fireAlert(env, payload) {
  // 1. Always persist in KV if bound (survives everything else failing)
  try {
    if (env && env.SUBMISSIONS) {
      const key = payload.kind + "_" + Date.now();
      await env.SUBMISSIONS.put(key, JSON.stringify(payload), { expirationTtl: 60 * 60 * 24 * 90 });
    }
  } catch (e) {}
  // 2. Fire webhook (Make/Zapier/SMS) — primary alert path
  let webhookOk = false;
  const url = (env && env.ALERT_WEBHOOK) || ALERT_WEBHOOK;
  if (url) {
    try {
      const res = await fetch(url, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });
      webhookOk = res.ok;
    } catch (e) {}
  }
  // 3. Email fallback — always send, regardless of webhook status. Double-belt.
  //    (If you only want email when the webhook fails, change to: if (!webhookOk) await sendFallbackEmail(env, payload);)
  await sendFallbackEmail(env, payload);
}

function html(body) {
  return new Response(body, { headers: { "Content-Type": "text/html; charset=utf-8", "Cache-Control": "public, max-age=300", "X-Content-Type-Options": "nosniff", "Strict-Transport-Security": "max-age=31536000; includeSubDomains" } });
}

export default {
  async fetch(request, env) {
    const url = new URL(request.url);
    const p = url.pathname;

    if (p === "/robots.txt") return new Response(ROBOTS, { headers: { "Content-Type": "text/plain" } });
    if (p === "/sitemap.xml") return new Response(SITEMAP, { headers: { "Content-Type": "application/xml" } });
    if (p === "/llms.txt") return new Response(LLMS_TXT, { headers: { "Content-Type": "text/plain; charset=utf-8" } });
    if ((p === "/privacy" || p === "/privacy/") && PRIVACY_HTML) return html(PRIVACY_HTML);
    if ((p === "/terms" || p === "/terms/") && TERMS_HTML) return html(TERMS_HTML);
    if (p === "/contact.vcf" || p === "/vcard") {
      return new Response(VCARD, {
        headers: {
          "Content-Type": "text/vcard; charset=utf-8",
          "Content-Disposition": "attachment; filename=\"contact.vcf\"",
          "Cache-Control": "public, max-age=3600",
        }
      });
    }

    // Instant search API — keyword + scored. Works without any AI binding.
    // If env.AI is bound (Cloudflare Workers AI), we also attempt semantic ranking.
    if (p === "/api/search" || p === "/search") {
      const q = (url.searchParams.get("q") || "").trim().toLowerCase();
      if (!q) return new Response(JSON.stringify({ ok: true, results: [], query: "" }), { headers: { "Content-Type": "application/json", "Access-Control-Allow-Origin": "*" } });
      const tokens = q.split(/\s+/).filter(Boolean);
      const scored = KB.map((item, i) => {
        const hay = (item.q + " " + item.a + " " + item.category).toLowerCase();
        let score = 0;
        for (const t of tokens) {
          if (!hay.includes(t)) continue;
          score += 1;
          if (item.q.toLowerCase().includes(t)) score += 2;
          if (item.category.toLowerCase().includes(t)) score += 1;
        }
        return { item, score, i };
      }).filter(r => r.score > 0).sort((a, b) => b.score - a.score || a.i - b.i).slice(0, 10);
      // Optional: Workers AI re-ranking if bound — graceful fallback
      try {
        if (env && env.AI && scored.length > 1) {
          // Leave scored as-is for now; a vector index can be added later via env.VECTORIZE
        }
      } catch (e) {}
      return new Response(JSON.stringify({ ok: true, query: q, results: scored.map(r => r.item) }), { headers: { "Content-Type": "application/json", "Access-Control-Allow-Origin": "*" } });
    }

    // Blog
    if (p === "/blog" || p === "/blog/") return html(BLOG_INDEX || HTML);
    if (p.startsWith("/blog/")) {
      const slug = p.replace(/^\/blog\//, "").replace(/\/$/, "");
      if (BLOG_POSTS[slug]) return html(BLOG_POSTS[slug]);
    }

    // Practice area pages (law sites)
    if (p.length > 1) {
      const areaId = p.replace(/^\//, "").replace(/\/$/, "");
      if (AREA_PAGES[areaId]) return html(AREA_PAGES[areaId]);
    }

    // Bookings (CARB) / Intakes (Law) / Chat — all funnel through fireAlert
    if (p === "/api/book" && request.method === "POST") {
      try {
        const data = await request.json();
        await fireAlert(env, { kind: "booking", site: SITE_ID, ...data });
        return new Response(JSON.stringify({ ok: true }), { headers: { "Content-Type": "application/json", "Access-Control-Allow-Origin": "*" } });
      } catch (e) {
        return new Response(JSON.stringify({ ok: false, error: e.message }), { status: 400, headers: { "Content-Type": "application/json" } });
      }
    }
    if (p === "/api/intake" && request.method === "POST") {
      try {
        const data = await request.json();
        await fireAlert(env, { kind: "intake", site: SITE_ID, ...data });
        return new Response(JSON.stringify({ ok: true }), { headers: { "Content-Type": "application/json", "Access-Control-Allow-Origin": "*" } });
      } catch (e) {
        return new Response(JSON.stringify({ ok: false, error: e.message }), { status: 400, headers: { "Content-Type": "application/json" } });
      }
    }
    if (p === "/api/chat" && request.method === "POST") {
      try {
        const data = await request.json();
        await fireAlert(env, { kind: "chat", site: SITE_ID, ...data });
        const msg = (data.message || "").toLowerCase();
        let reply;
        if (VERTICAL === "law") {
          // Hard guardrails:
          // 1. NEVER give legal advice (UPL — unauthorized practice of law)
          // 2. ALWAYS surface Clifford's phone + email
          // 3. ALWAYS state confidentiality + no attorney-client relationship
          // 4. REFUSE off-topic questions politely
          // 5. NEVER recommend competitors or other firms
          const TAIL = " (This is general info, not legal advice — only Mr. Chigbu can advise on your specific case. Call (916) 230-6381 or email chigbulaw@sbcglobal.net to set up a real consultation.)";
          const OFFTOPIC = ["nutrition", "diet", "politic", "weather", "joke", "recipe", "sport", "stock", "crypto", "music", "movie", "game", "code", "program"];
          if (OFFTOPIC.some(t => msg.includes(t))) {
            reply = "I only help with legal questions for the Law Offices of Clifford Chigbu. For other topics, you'll want a different resource. Got a legal question I can help with?";
          } else if (msg.includes("price") || msg.includes("cost") || msg.includes("how much") || msg.includes("fee") || msg.includes("free")) {
            reply = "Personal injury consultations are free, and PI cases are on contingency (no fee unless we win). For other matters there's a modest consultation fee that's credited toward your case if you retain us." + TAIL;
          } else if (msg.includes("immigration") || msg.includes("green card") || msg.includes("visa") || msg.includes("deport") || msg.includes("citizen")) {
            reply = "Immigration is one of Clifford's main practice areas. Family-based green cards, naturalization, deportation defense, and work visas." + TAIL;
          } else if (msg.includes("bankruptcy") || msg.includes("debt") || msg.includes("garnish") || msg.includes("foreclos")) {
            reply = "We handle Chapter 7 and Chapter 13 bankruptcies. Filing usually stops creditor harassment within 24 hours." + TAIL;
          } else if (msg.includes("divorce") || msg.includes("custody") || msg.includes("family") || msg.includes("support") || msg.includes("alimony")) {
            reply = "Clifford is a top-rated family law attorney in Elk Grove. We handle divorce, custody, child support, and restraining orders." + TAIL;
          } else if (msg.includes("accident") || msg.includes("injury") || msg.includes("hurt") || msg.includes("crash")) {
            reply = "Personal injury consultations are free and there's no fee unless we win. The sooner you call, the better — California has strict deadlines on injury claims." + TAIL;
          } else if (msg.includes("contract") || msg.includes("business") || msg.includes("llc") || msg.includes("partnership")) {
            reply = "We handle contract review, drafting, business formation, and disputes. Flat-rate contract reviews available." + TAIL;
          } else if (msg.includes("hour") || msg.includes("open") || msg.includes("when") || msg.includes("schedule")) {
            reply = "We're open Monday–Friday 8:30 AM to 6:00 PM, with after-hours by appointment.";
          } else if (msg.includes("address") || msg.includes("location") || msg.includes("where") || msg.includes("office")) {
            reply = "Our office is at 4815 Laguna Park Dr, Suite C, Elk Grove, CA 95758. We also do phone and video consultations.";
          } else if (msg.includes("review") || msg.includes("rating") || msg.includes("good")) {
            reply = "We're rated 4.8 stars on Google with 24+ client reviews. You can read them all on Google Maps.";
          } else if (msg.includes("language") || msg.includes("speak")) {
            reply = "English is our primary language, and we can arrange interpreters for Spanish and other languages on request.";
          } else if (msg.includes("am i") || msg.includes("can i") || msg.includes("should i") || msg.includes("will i")) {
            // User is asking for legal advice — REFUSE and redirect
            reply = "That's exactly the kind of question Clifford should answer in person — every case is different and the right answer depends on details I can't see. The best thing is to call (916) 230-6381 or fill out the intake form on this page. Everything is confidential.";
          } else {
            reply = "I can help with general questions about Family Law, Immigration, Personal Injury, Bankruptcy, and Business law in California. For anything case-specific, drop your phone number and Clifford will follow up — or call (916) 230-6381 directly. Email: chigbulaw@sbcglobal.net.";
          }
        } else {
          // CARB defaults
          if (msg.includes("price") || msg.includes("cost") || msg.includes("how much")) {
            reply = "OBD test (2013+) is $119, OVI smoke (2012 & older) is $219. Motorhomes same pricing.";
          } else if (msg.includes("hours") || msg.includes("when") || msg.includes("weekend")) {
            reply = "We run 24/7, weekends included. We'll come to your yard, lot, or jobsite.";
          } else if (msg.includes("schedule") || msg.includes("book") || msg.includes("appointment")) {
            reply = "Easy — leave your phone number here and we'll text you back, or call us at (916) 230-6381.";
          } else {
            reply = "Got it — alerting the Elk Grove crew now. Drop your phone number and we'll text you in a few minutes. Or call (916) 230-6381.";
          }
        }
        return new Response(JSON.stringify({ ok: true, reply }), { headers: { "Content-Type": "application/json", "Access-Control-Allow-Origin": "*" } });
      } catch (e) {
        return new Response(JSON.stringify({ ok: false, error: e.message }), { status: 400, headers: { "Content-Type": "application/json" } });
      }
    }

    return html(HTML);
  }
};
